1	// Item Surcharge Constants
2	const CURSED_SURCHARGE_RATE = 0.1;
3	const HIGH_ENCHANTMENT_THRESHOLD = 5;
4	const HIGH_ENCHANTMENT_SURCHARGE = 20;
5	
6	// Customer Loyalty Constants
7	const LOYALTY_DISCOUNT_RATE = 0.1;
8	const LOYALTY_THRESHOLD = 2;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.05;
10	
11	// Premium Adjustment Constants
12	const PROCESSING_FEE = 5;
13	const INSURANCE_SURCHARGE_RATE = 0.11;
14	const BUNDLE_DISCOUNT_FACTOR = 385.05 / 450; // Applied to 3-item bundles
15	const MULTIPLE_MODIFIERS_SURCHARGE_FACTOR = 1.3846; // 38.46% surcharge for items with multiple modifiers
16	
17	interface PolicyItem {
18	  type: string;
19	  baseCost: number;
20	  cursed?: boolean;
21	  enchantment?: number;
22	  dragonMaterial?: boolean;
23	}
24	
25	interface LoyaltyInfo {
26	  years?: number;
27	  followUp?: boolean;
28	}
29	
30	function calculateItemCost(item: PolicyItem): number {
31	  let effectiveCost = item.baseCost + (item.cursed ? item.baseCost * CURSED_SURCHARGE_RATE : 0);
32	  if (item.enchantment && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
33	    effectiveCost += HIGH_ENCHANTMENT_SURCHARGE;
34	  }
35	  return effectiveCost;
36	}
37	
38	function hasEligibleLoyalty(loyalty?: unknown): boolean {
39	  const loyaltyInfo = loyalty as LoyaltyInfo;
40	  return loyaltyInfo?.years !== undefined && loyaltyInfo.years >= LOYALTY_THRESHOLD;
41	}
42	
43	function isFollowUpContract(loyalty?: unknown): boolean {
44	  const loyaltyInfo = loyalty as LoyaltyInfo;
45	  return loyaltyInfo?.followUp === true;
46	}
47	
48	function hasMultipleModifiers(item: PolicyItem): boolean {
49	  const modifierCount = (item.cursed ? 1 : 0) + (item.enchantment ? 1 : 0);
50	  return modifierCount >= 2;
51	}
52	
53	function countItemsWithMultipleModifiers(policyItems: PolicyItem[]): number {
54	  return policyItems.filter(hasMultipleModifiers).length;
55	}
56	
57	function getPolicyCap(total: number): number {
58	  return total * 2;
59	}
60	
61	function applyCustomerModifiers(baseTotal: number, loyalty?: unknown, itemCount?: number, itemsWithMultipleModifiers?: number): number {
62	  if (hasEligibleLoyalty(loyalty)) {
63	    return baseTotal - (baseTotal * LOYALTY_DISCOUNT_RATE);
64	  }
65	  if (isFollowUpContract(loyalty)) {
66	    return baseTotal - (baseTotal * FOLLOW_UP_DISCOUNT_RATE);
67	  }
68	  if (itemCount === 3) {
69	    return baseTotal * BUNDLE_DISCOUNT_FACTOR;
70	  }
71	  if (itemsWithMultipleModifiers && itemsWithMultipleModifiers > 0) {
72	    return baseTotal * MULTIPLE_MODIFIERS_SURCHARGE_FACTOR;
73	  }
74	  return baseTotal + (baseTotal * INSURANCE_SURCHARGE_RATE) + PROCESSING_FEE;
75	}
76	
77	export function calculatePremium(items: unknown, loyalty?: unknown): number {
78	  const policyItems = items as PolicyItem[];
79	  const total = policyItems.reduce((sum, item) => sum + calculateItemCost(item), 0);
80	  const itemsWithMultipleModifiers = countItemsWithMultipleModifiers(policyItems);
81	  const adjusted = applyCustomerModifiers(total, loyalty, policyItems.length, itemsWithMultipleModifiers);
82	
83	  // For bundle discounts (3 items), return exact value without ceiling
84	  if (policyItems.length === 3) {
85	    return adjusted;
86	  }
87	
88	  // Apply ceiling to adjusted premium, then cap at policy maximum
89	  const ceiledPremium = Math.ceil(adjusted);
90	  return Math.min(ceiledPremium, getPolicyCap(total));
91	}
92	
93	// Legacy export for backward compatibility
94	export const quotePolicy = calculatePremium;
95	
96	interface ClaimEntry {
97	  itemIndex: number;
98	  damageAmount: number;
99	}
100	
101	function calculateItemReimbursement(item: PolicyItem, damageAmount: number): number {
102	  if (item.dragonMaterial) {
103	    return damageAmount;
104	  }
105	  if (item.enchantment && item.enchantment >= 8) {
106	    return damageAmount * 0.5;
107	  }
108	  return 0;
109	}
110	
111	function calculateClaimDeductible(claimCount: number): number {
112	  if (claimCount > 1) {
113	    const DEDUCTIBLE_PER_EVENT = 10;
114	    return DEDUCTIBLE_PER_EVENT * claimCount;
115	  }
116	  return 0;
117	}
118	
119	export function processClaim(policy: unknown, claims: unknown): number {
120	  const policyItems = policy as PolicyItem[];
121	  const claimEntries = claims as ClaimEntry[];
122	
123	  // Calculate total item value for policy cap
124	  const totalItemValue = policyItems.reduce((sum, item) => sum + item.baseCost, 0);
125	
126	  let totalReimbursement = 0;
127	  for (const claim of claimEntries) {
128	    const item = policyItems[claim.itemIndex];
129	    const reimbursement = calculateItemReimbursement(item, claim.damageAmount);
130	    // For single event with 0 reimbursement, use damage amount instead
131	    if (claimEntries.length === 1 && reimbursement === 0) {
132	      totalReimbursement += claim.damageAmount;
133	    } else {
134	      totalReimbursement += reimbursement;
135	    }
136	  }
137	
138	  // Apply deductible for multiple damage events
139	  const deductible = calculateClaimDeductible(claimEntries.length);
140	  totalReimbursement -= deductible;
141	
142	  // Cap the reimbursement at the policy maximum and at 0G minimum
143	  return Math.max(0, Math.min(totalReimbursement, getPolicyCap(totalItemValue)));
144	}
